interface AIServiceConfig {
  apiKey?: string;
  userTier: 'free' | 'pro';
  byokKey?: string;
}

interface GenerationRequest {
  prompt: string;
  designSystem?: string;
  componentType?: string;
}

interface GenerationResponse {
  html: string;
  css: string;
  explanation: string;
}

