  private config: AIServiceConfig = {
    userTier: 'free'
  };

  // Free tier models (no cost)
  private freeModels = [
    'mistralai/mistral-small-3.2-24b-instruct:free',
    'microsoft/phi-3-mini-4k-instruct:free',
    'huggingfaceh4/zephyr-7b-beta:free'
