    'anthropic/claude-3.5-sonnet',
    'openai/gpt-4-turbo',
    'openai/gpt-4o'
  ];

  updateConfig(config: Partial<AIServiceConfig>) {
    this.config = { ...this.config, ...config };
  }

  private getSelectedModel(): string {
    if (this.config.userTier === 'pro') {
      if (this.config.byokKey) {
        return 'anthropic/claude-3.5-sonnet'; // Use best model with BYOK
      }
      return this.config.apiKey ? 'anthropic/claude-3.5-sonnet' : this.freeModels[0];
    }
    return this.freeModels[0]; // Free users get free models
  }

  private getApiKey(): string {
    // Priority: BYOK > User's paid key > Default free key
    if (this.config.byokKey) return this.config.byokKey;
    if (this.config.apiKey) return this.config.apiKey;
    return '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'; // Free tier key provided
  }

  private generateSystemPrompt(designSystem?: string): string {
    const systemPrompt = `You are an expert UI/UX developer who creates beautiful, functional React components. 

IMPORTANT RULES:
1. Generate ONLY valid HTML and CSS code
2. Use modern, clean design principles
3. Make components responsive and accessible
4. Include hover states and transitions
5. Use semantic HTML elements
6. Ensure high contrast and readability
7. Return valid JSON with html, css, and explanation fields

${designSystem && designSystem !== 'No design system' ? 
  `DESIGN SYSTEM: Follow ${designSystem} design patterns and component styles.` : 
  'DESIGN SYSTEM: Use a clean, modern design with subtle shadows, rounded corners, and professional spacing.'
}

RESPONSE FORMAT:
{
  "html": "<div>Your HTML here</div>",
  "css": ".component { /* Your CSS here */ }",
  "explanation": "Brief explanation of the component and its features"
}`;

    return systemPrompt;
  }

  async generateComponent(request: GenerationRequest): Promise<GenerationResponse> {
    const model = this.getSelectedModel();
    const apiKey = this.getApiKey();

    try {
      // Always try real AI generation first, fallback to mock on error

      const response = await fetch('https://openrouter.ai/api/v1/chat/completions', {
        method: 'POST',
        headers: {
          'Authorization': `Bearer ${apiKey}`,
          'Content-Type': 'application/json',
          'HTTP-Referer': window.location.origin,
          'X-Title': 'MagicPath UI Generator'
        },
        body: JSON.stringify({
          model,
          messages: [
            {
              role: 'system',
              content: this.generateSystemPrompt(request.designSystem)
            },
            {
              role: 'user',
              content: `Create a ${request.prompt}. Make it production-ready with proper styling.`
            }
          ],
          temperature: 0.7,
          max_tokens: 2000,
          top_p: 0.9
        })
      });

      if (!response.ok) {
        throw new Error(`API request failed: ${response.statusText}`);
      }

      const data = await response.json();
      const content = data.choices?.[0]?.message?.content;

      if (!content) {
        throw new Error('No content received from AI');
      }

      // Try to parse JSON response
      try {
        const parsed = JSON.parse(content);
        return {
          html: parsed.html || '',
          css: parsed.css || '',
          explanation: parsed.explanation || 'Component generated successfully!'
        };
      } catch {
        // Fallback: try to extract HTML/CSS from text response
        return this.parseTextResponse(content);
      }

    } catch (error) {
      console.error('AI Generation Error:', error);

      // Fallback to mock generation on error
      return this.generateMockComponent(request);
    }
  }

  private parseTextResponse(content: string): GenerationResponse {
    // Extract HTML
    const htmlMatch = content.match(/```html\n([\s\S]*?)\n```/) || 
                     content.match(/<[^>]+>[\s\S]*<\/[^>]+>/);

    // Extract CSS
    const cssMatch = content.match(/```css\n([\s\S]*?)\n```/) ||
                    content.match(/\.[\w-]+\s*\{[\s\S]*?\}/);

    return {
      html: htmlMatch ? htmlMatch[1] || htmlMatch[0] : '<div>Generated content</div>',
      css: cssMatch ? cssMatch[1] || cssMatch[0] : '.component { padding: 20px; }',
      explanation: 'Component generated from AI response'
    };
  }

