    // Find matching template
    const promptLower = request.prompt.toLowerCase();
    const template = Object.keys(templates).find(key => 
      promptLower.includes(key) && key !== 'default'
    ) || 'default';

    return templates[template as keyof typeof templates] || templates.default;
  }

  // Check if user can access pro features
  canAccessProFeatures(): boolean {
    return this.config.userTier === 'pro' && (this.config.apiKey || this.config.byokKey);
  }

  // Get current model info for UI display
  getCurrentModelInfo(): { name: string; tier: string; cost: string } {
    const model = this.getSelectedModel();

    if (this.freeModels.includes(model)) {
      return {
        name: 'Phi-3 Mini',
        tier: 'Free',
        cost: 'Free forever'
      };
    }

    if (this.config.byokKey) {
      return {
        name: 'Claude 3.5 Sonnet',
        tier: 'BYOK',
        cost: 'Your API costs'
      };
    }

    return {
      name: 'Claude 3.5 Sonnet',
      tier: 'Pro',
      cost: 'Included in Pro'
    };
  }
